def retry(times):
    def decorator(f):
        def wrapper(*args, **kwargs):
            for _ in range(times):
                try:
                    return f(*args, **kwargs)
                except Exception:
                    pass
        return wrapper
    return decorator

from functools import wraps
def log_call(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        print(f'Calling {f.__name__}')
        return f(*args, **kwargs)
    return wrapper

